"use strict";
/* =====================================================================
 * content/events-sudden.js —— 内容模块：突发人生事件（戏剧性·低频·改命）
 * ---------------------------------------------------------------------
 * 经典 <script>，运行在全局作用域。直接向核心层已定义的全局 EVENTS 数组
 * 追加事件（EVENTS.push({...})）。复用全局 helper：
 *   add / flag / has / pick / rnd / byClass / classTier。
 * 不 import、不包 IIFE、不重定义任何 helper。
 *
 * 主题：车祸、突发重病、至亲离世、配偶离世、绑架、电信诈骗、被偷被抢、
 *       工伤、自然灾害、宠物离世、老友重逢、被裁后的至暗时刻，以及若干
 *       其它突发（中奖被骗、医闹、邻里纠纷、捡到巨款、被冤枉、网暴）。
 *   多为 once:true（一辈子一次），ambient:true（每周随机抽取触发）。
 * ===================================================================== */

// —— 1. 车祸 ——
EVENTS.push({
  id: "ev_sudden_caraccident",
  module: "sudden",
  ambient: true,
  once: true,
  cond: (s) => s.age >= 20,
  title: "🚑 一场措手不及的车祸",
  text: (s) => "刺耳的急刹声撕开了平静的午后。玻璃碎裂的脆响，金属扭曲的闷哼，然后是一片诡异的、不属于这个世界的安静。一辆闯红灯的车把你结结实实撞飞了出去，天地颠倒，时间被拉成了慢镜头，你甚至来得及看清自己被甩起的鞋子。再睁眼时，你脸贴着冰冷的柏油路，路面的颗粒硌着脸颊。疼痛起初是麻木的，随后像决堤的潮水，一寸一寸把你淹没。视线边缘有暗红的东西在慢慢洇开。远处，一声鸣笛由远及近——你忽然意识到，那是为你而来的。原来一辈子，真的可以在一个红灯的瞬间，被拦腰折断。",
  choices: [
    { label: "叫救护车，正规走程序", effect: (s) => {
        add(s, "health", -28); add(s, "stress", 16);
        const cost = byClass(s, { poor: 18000, mid: 40000, rich: 60000 });
        add(s, "cash", -cost);
        flag(s, "car_crash_survivor");
        if (rnd(0.5)) { add(s, "cash", Math.round(cost * 0.6)); return byClass(s, {
          poor: `你被抬上救护车，担架晃晃悠悠，天花板的灯一盏盏从眼前掠过。ICU 的玻璃门后，监护仪的滴答声里，是一台计价器般疯狂跳动的账单。前后搭进去 ¥${cost.toLocaleString()}，对方全责，可赔偿款像挤牙膏一样，你为这笔钱跑断了腿、赔过笑、低过头、在调解室里咽下过多少不甘。命留住了，钱却把这个家压得喘不过气。从此每次过马路，你都要先深吸一口气，再三确认两边——那一秒的飞起，成了刻进骨子里的本能恐惧。`,
          mid: `急诊、缝合、住院、复健，一套流程走下来，账单累计 ¥${cost.toLocaleString()}，好在对方保险赔回了大半。命是保住了，断的骨头会长好，缝的口子会结疤。可有些东西回不来了——那种「生活会随机抽走你一块，而你毫无还手之力」的恐惧，从此像背景噪音一样，再没真正散去过。`,
          rich: `最好的医院、单人病房、二十四小时私人康复师，¥${cost.toLocaleString()} 你连眼都没眨。律师团队把对方告到赔得心服口服，连那个司机庭后都跑来给你鞠躬。该有的都有了。可深夜里，输液管滴答作响，你盯着天花板忽然彻骨地明白：钱能买回最好的医生、最贵的器械、健康的每一个零件，唯独买不回那撞击前一秒、世界还完好无损时的那份安全感。`
        }); }
        return `手术很成功，医生说恢复得不错。可你心里清楚，你落下了一道阴雨天就隐隐作痛的旧伤——身体替你记住了那场车祸，往后每个变天的日子都来提醒你。¥${cost.toLocaleString()} 的医药费像一道疤，刻在账户上；而那一秒的天旋地转，刻在记忆里，更深。`;
      } },
    { label: "对方塞钱「私了」，你忍痛答应", effect: (s) => {
        add(s, "health", -34); add(s, "stress", 10);
        flag(s, "car_crash_survivor");
        if (rnd(0.4)) { add(s, "cash", 8000); add(s, "mood", -6); return "对方蹲下来，掏出一沓还带着体温的现金塞进你手里，连声说「都不容易，都不容易，别报警了行不行」。你头还晕着，贪图省事，也心软，就收下了。三天后，看似不重的伤忽然恶化，你被紧急送进医院。躺在病床上算账时你才明白：那点钱连药费的零头都不够，更别提对方早已联系不上。私了私了，到头来，私下了结掉的只有你自己的健康。"; }
        add(s, "cash", 15000); add(s, "mood", -3);
        return "你接过对方的钱，咬咬牙，摆摆手，自己一瘸一拐地回了家养伤。运气还算眷顾，没落下什么大毛病，钱也实打实进了口袋。只是往后许多个夜里，翻身时那一阵深处的钝痛总会准时醒来，像个不肯走的提醒：有些便宜，是拿命去换的。";
      } },
    { label: "我没事！硬撑着爬起来走人", effect: (s) => {
        flag(s, "car_crash_survivor");
        if (rnd(0.55)) { add(s, "health", -42); add(s, "stress", 18); add(s, "cash", -30000); return "你咬着牙撑起身，摆摆手对围观的人说「我没事」，硬是一步步走开了，连联系方式都没留。可你不知道，撞击在身体里埋下了一颗看不见的雷。当晚内出血发作，疼得你冷汗淋漓蜷成一团，同事砸开门把你紧急送医，进了手术室，差一点就没能再出来。¥30,000 的账单，和醒来时身边人那句又气又怕的「你逞什么强啊」，是这次倔强要付的代价。"; }
        add(s, "health", -12);
        return "你拍拍身上的尘土，活动了下四肢，居然真的没什么大碍，便一瘸一拐地走回了家。直到关上门，那股劫后余生的后怕才迟迟涌上来——原来刚才离死亡只隔着那么薄的一层。这一夜你抱着被子，哆嗦了半宿也没睡着。";
      } }
  ]
});

// —— 2. 突发重病（确诊大病）——
EVENTS.push({
  id: "ev_sudden_illness",
  module: "sudden",
  ambient: true,
  once: true,
  cond: (s) => s.age >= 35,
  title: "🏥 一纸确诊书",
  text: (s) => "只是一次单位组织的例行体检，你本没当回事。可那份复查通知来得猝不及防，电话那头的语气客气得反常。诊室里，医生反复看了两遍片子，又抬眼看了看你，才把灯箱上的影像轻轻推到你面前。他的声音压得很低，像怕惊扰了什么：「别太紧张……但需要尽快住院，做进一步治疗。」时间在那一刻凝固了。那个你只在新闻和别人的故事里听过的病名，此刻白纸黑字、清清楚楚地，落在了你自己的名字后面。你张了张嘴，却发不出声音。走廊的灯惨白惨白，人来人往的脚步声忽然变得很远，你扶住墙，才发现腿在发软。",
  choices: [
    { label: "积极治疗，砸钱保命", effect: (s) => {
        add(s, "health", -30); add(s, "stress", 20); add(s, "mood", -12);
        flag(s, "chronic_illness");
        const cost = byClass(s, { poor: 120000, mid: 250000, rich: 500000 });
        add(s, "cash", -cost);
        return byClass(s, {
          poor: `你卖了能卖的一切——首饰、电动车、甚至悄悄打听过房子能押多少。又咬着牙在水滴筹上写下自己的故事，配上憔悴的照片，低头向素不相识的全世界求助。一笔一笔，凑出了 ¥${cost.toLocaleString()}。化疗的日子里你掉光了头发，呕得吃不下东西，半夜疼得睡不着，就睁眼盯着天花板，一遍遍在心里算账：还差多少，还能撑几个疗程。你最怕的从来不是死，是拖累。穷人生一场大病，是把全家人一起拽进同一个深不见底的坑。`,
          mid: `¥${cost.toLocaleString()}，几乎掏空了你大半生的积蓄，连同那份当年咬牙买下、如今救了命的「重疾险」。一轮轮治疗下来，你瘦了整整一圈，镜子里的人陌生得让你愣神，但好歹——指标终于稳住了，医生脸上有了笑意。躺在病床上数着输液的滴速，你第一次如此真切地懂得那句老话：健康才是最前面的那个 1，事业、房子、存款、体面，全是它后面的 0。1 没了，后面再多的 0，也只是 0。`,
          rich: `你连夜飞去全国最好的医院，托关系请来挂号要排半年的专家会诊，¥${cost.toLocaleString()} 在你的账户里只是一行数字的轻微变动。最新的靶向药、安静的单人病房、二十四小时的私人护理，能上的全上了，一刻没耽误。钱在这一刻成了实打实的护城河，把死神挡在了门外几步远的地方。可城墙再高也挡不住夜。每当深夜无人、护士关灯离开，你独自躺在黑暗里听着自己的心跳，才发现：在这件事上，你和隔壁病房那个掏不出钱的人，怕得一模一样。`
        });
      } },
    { label: "保守治疗，听天由命", effect: (s) => {
        add(s, "health", -20); add(s, "mood", -8); add(s, "stress", 6);
        flag(s, "chronic_illness");
        if (rnd(0.5)) { add(s, "mood", 8); add(s, "insight", 3); return "你选择了不那么激进、不那么伤元气的方案，把省下的精力和时间，都留给了家人，留给了那些一直想做却总说「以后再说」的事。你去看了一次海，陪父母吃了好几顿从前总抽不出空的饭。意外的是，当你不再和病死磕、把心态彻底放平之后，身体竟比所有人预想的都要稳。生死走到面前掀了底牌，你反倒把许多事看得通透了——原来活着本身，就已经是答案。"; }
        add(s, "health", -12);
        return "你不想拖累任何人，于是选了最省钱、最不声张的法子，能扛就自己扛着。病情像潮汐一样时好时坏，像一柄始终悬在头顶、不知何时落下的剑。日子久了，你竟也学会了和它平静共处——按时吃药，好好吃饭，不再为明天惊慌。你慢慢懂得把每一个平平无奇、还能下床走动的清晨，都当成是命运额外赊给你的、要好好珍惜的一天。";
      } },
    { label: "怀疑误诊，跑遍各大医院复核", effect: (s) => {
        add(s, "stress", 12); add(s, "cash", -8000);
        if (rnd(0.25)) { add(s, "mood", 20); add(s, "health", 4); flag(s, "false_alarm"); return "你死活不肯相信，揣着片子辗转三家医院、挂遍了能挂的专家号。就在你几乎绝望时，结果竟峰回路转——一位老主任反复比对后告诉你，前一家把影像看重了，你的情况远远没有那么糟，调理一段时间就好。那一句话，像是从悬崖边把你拽了回来。走出医院大门那一刻，平日里再寻常不过的阳光，从没这样耀眼、这样好看过。这条命，简直像是白捡回来的。"; }
        add(s, "health", -22); add(s, "mood", -14); flag(s, "chronic_illness");
        return "你揣着一线侥幸跑了一大圈，挂号、排队、抽血、复查，可所有医生最终给出的结论惊人地一致，没有一个人松口说你听错了。否认、愤怒、和命运讨价还价、试图蒙混过关……心理学上那几个阶段，你在这些天里一个不落地走了一遍。兜兜转转，你终究还是要回到那间最初的诊室，坐回那张椅子，面对它。而这一圈下来白白耽误的日子，也成了整个治疗里最昂贵、最不该交的一笔「学费」。";
      } }
  ]
});

// —— 3. 父母/至亲离世 ——
EVENTS.push({
  id: "ev_sudden_parentdeath",
  module: "sudden",
  ambient: true,
  once: true,
  cond: (s) => s.age >= 30,
  title: "🕯️ 那通深夜的电话",
  text: (s) => "凌晨三点，手机在床头柜上疯狂震动，屏幕的冷光一下下刺进黑暗。还没接通，你的心就先沉了下去——这个点的电话，从来没有好消息。那头是亲戚带着哭腔、断断续续的声音：「快回来……快回来……你爸/妈……不行了，医生说就这两天了……」你的脑子「嗡」地一声炸成了空白，握着手机的手不受控制地发抖，喉咙发紧，一个字也吐不出来。从你睁眼记事起就一直在那里、一直在的那个人，那个永远会为你留一盏灯的人，竟要从这个世界上，永远地、再也不回来地，消失了。",
  choices: [
    { label: "连夜赶回，陪ta走最后一程", effect: (s) => {
        add(s, "mood", -28); add(s, "stress", 14); add(s, "health", -6);
        flag(s, "lost_parent");
        if (has(s, "warm_family") || rnd(0.5)) { add(s, "mood", 6); add(s, "insight", 3); return "你在最后一刻冲进病房，赶上了。你握住那只熟悉又陌生的手——还是从前那双布满老茧、牵过你过马路、为你撑过一片天的手，此刻却轻得像一片要被风带走的叶子。你们没说太多话，那只手回握了你一下，你们彼此都懂了。送别那天大雨倾盆，雨水混着泪水模糊了视线。撑着伞站在墓前，你忽然就在一夜之间长大了——从今往后，那个为全家人遮风挡雨的人，换成了你。心口被生生掏空了一块，你知道，这个洞此生再也填不满了。"; }
        add(s, "mood", -8);
        return "你订了最早的票，一路狂奔，闯过红灯、追过站台，可命运偏偏只差了那么几个小时——你还是没能见上最后一面。灵堂前，遗像里的人在对你温和地笑着。你「扑通」一声跪倒在地，再也撑不住。那句酝酿了很久、却总想着「等下次回家再说」的「对不起」和「我爱你」，从此再没有了出口，成了余生里最深、最隐隐作痛的遗憾。「子欲养而亲不待」——这七个字你听过无数遍，却从没想过，有一天会这样血淋淋地，落在自己身上。";
      } },
    { label: "操办身后事，强撑着把家撑起来", effect: (s) => {
        add(s, "mood", -22); add(s, "stress", 18); add(s, "health", -8);
        flag(s, "lost_parent");
        const cost = byClass(s, { poor: 30000, mid: 60000, rich: 120000 });
        add(s, "cash", -cost);
        return `你甚至顾不上好好崩溃一场，因为有一整摊事压在肩上，逼着你站直。讣告、灵堂、停灵、答谢前来吊唁的亲友、应付一桩桩繁琐的人情往来、还有那 ¥${cost.toLocaleString()} 的丧葬开销……你像上紧了发条的机器一样连轴运转，接电话、做决定、强撑着对每个人说「谢谢，节哀」。直到一切尘埃落定，深夜里你独自坐回那间空荡荡、再也没人等你的老屋，按亮灯，看着熟悉的一切都还在、唯独人不在了——压抑了几天的眼泪，才终于决了堤。从这一晚起，你成了这个家里那座再也不能倒下、也不被允许倒下的山。`;
      } },
    { label: "悲痛欲绝，整个人垮了下去", effect: (s) => {
        add(s, "mood", -34); add(s, "stress", 22); add(s, "health", -14);
        flag(s, "lost_parent"); flag(s, "grief_depressed");
        return "葬礼结束后，你把自己反锁在房间里，拉上窗帘，不吃不喝，不接任何人的电话。世界的声音被关在了门外。那种失去至亲的痛不是抽象的悲伤，而是具体的、生理性的、撕扯着五脏六腑的疼——像有人趁你不备，活生生从你身上剜走了一块肉，伤口大敞着，连血都来不及流。你一遍遍翻看旧照片、旧聊天记录，听ta留下的最后一段语音，直到再也分不清白天黑夜。很长很长一段时间里，你都困在那口又黑又冷的深井底，看得见井口的光，却怎么也爬不上去。后来你才慢慢明白：有些伤口，时间能做的，至多是让它结一层薄薄的痂，让它不再随时溃烂——却永远无法让它，真正消失。";
      } }
  ]
});

// —— 4. 配偶离世 ——
EVENTS.push({
  id: "ev_sudden_spousedeath",
  module: "sudden",
  ambient: true,
  once: true,
  cond: (s) => has(s, "married") && s.age >= 45 && !has(s, "widowed"),
  title: "💔 白头之约，半路别离",
  text: (s) => `毫无征兆的一天，${s.partnerName || "ta"} 就这样走了。早上还在抱怨有点不舒服，还说着晚上想吃什么——可能是一场来势汹汹的急病，可能是一次无妄的意外，快得让你的脑子彻底跟不上，来不及反应，来不及说一句「我爱你」，来不及好好告别。那个曾握着你的手许诺要陪你看遍每一场夕阳、要和你慢慢变老一直到白头的人，毫无商量地，把后半生那条原本说好要并肩走完的路，单单丢给了你一个人。你失魂落魄地回到家，推开门——衣架上还挂着 ${s.partnerName || "ta"} 的外套，杯子里还剩半杯凉透的茶，空气里、枕头上、每一样东西上，都还残留着 ${s.partnerName || "ta"} 的温度和气息。仿佛ta只是出了趟门，下一秒就会回来。可你知道，不会了。`,
  choices: [
    { label: "把悲伤藏好，为孩子撑住这个家", effect: (s) => {
        add(s, "mood", -30); add(s, "stress", 16); add(s, "health", -8);
        flag(s, "widowed");
        if (has(s, "has_kid")) { add(s, "mood", 6); return `你把所有的悲伤都摁了下去，在孩子面前装作坚强，挤出笑容，告诉他们「爸爸/妈妈只是去了很远的地方」。只有等孩子睡熟，深夜独自坐在客厅，你才敢抱着 ${s.partnerName || "ta"} 那件还没来得及洗的衣服，把脸埋进去，无声地、整个肩膀都在抖地落泪。你一遍遍对自己说：不能倒，绝对不能倒，现在你是孩子在这世上唯一的依靠了。就是这份沉甸甸的责任，成了你硬撑着活下去的、最后也最坚硬的那一根支柱。`; }
        return `葬礼之后，偌大的房子里，只剩下你一个人和满屋子的回声，安静得能清清楚楚听见自己的心跳。你像往常一样烧饭，下意识地摆出两副碗筷，端上桌才猛地反应过来——又默默地，把那一副收了回去。你给ta常坐的那把椅子留着位置，睡觉时还习惯性地往床的一侧靠。原来这世上最难的，从来不是那一句正式的告别；是往后成千上万个独自醒来的清晨，伸手一摸，身边空空荡荡，而你要重新想起来一次：哦，对了，ta已经不在了。`;
      } },
    { label: "整理遗物，与回忆和解", effect: (s) => {
        add(s, "mood", -24); add(s, "stress", 10); add(s, "insight", 4);
        flag(s, "widowed");
        if (rnd(0.5)) { add(s, "mood", 10); return `你足足攒了很久的勇气，才敢推开那扇门，开始整理 ${s.partnerName || "ta"} 的遗物。可这一整理，竟整理出了大半生的光阴——泛黄卷边的合影里你们还那么年轻；ta 偷偷藏在书页里、写满了笨拙情话的小纸条；还有一份没来得及送出、没拆封的礼物，标签上是你的名字……你坐在地板上，哭了又笑，笑着笑着又哭。原来在你没察觉的那些寻常日子里，你们的爱，早就把生活的每一个犄角旮旯都悄悄填满了。捧着这些失而复得的温暖，你擦干眼泪，做了个决定：往后的日子，你要连 ${s.partnerName || "ta"} 那一份，一起好好地、认真地过下去。`; }
        add(s, "mood", -6);
        return `你一件一件，慢慢地抚摸着 ${s.partnerName || "ta"} 留下的东西——用旧的钢笔、看了一半折着角的书、那件你最喜欢ta穿的衬衫。每一样上面都有ta的影子，每一样碰上去，都是一道还没结疤的伤口。你最终把它们仔仔细细地叠好、收进一个箱子，扣上扣子，锁好，推进了柜子最深处。生活总还要继续，你对自己说。可你心里清楚得很，从今天起，有一扇门，已经为 ${s.partnerName || "ta"} 永远地、轻轻地，关上了。`;
      } },
    { label: "一蹶不振，把自己也封闭起来", effect: (s) => {
        add(s, "mood", -36); add(s, "stress", 20); add(s, "health", -16);
        flag(s, "widowed"); flag(s, "grief_depressed");
        return `从那以后，你不再出门，不再接电话，不再见任何人。窗帘常年拉着，你常常对着 ${s.partnerName || "ta"} 的照片，从天亮一动不动地坐到天黑，嘴里有一搭没一搭地说着只有你们俩才懂的话。朋友轮番上门劝慰，那些「要往前看」「ta 也希望你好好的」，你一句也听不进去，也不想听。失去挚爱的痛没有惊天动地，它像一片潮湿阴冷的霉斑，无声无息地，一点点爬满了你余下的整个人生。有人说，时间会治愈一切——可对你而言，时间从不曾治愈什么；它只是让你，越来越习惯于这份无边无际、与你余生作伴的思念。`;
      } }
  ]
});

// —— 5. 遭遇绑架 ——
EVENTS.push({
  id: "ev_sudden_kidnap",
  module: "sudden",
  ambient: true,
  once: true,
  cond: (s) => classTier(s) >= 2 && s.age >= 25,
  title: "🪢 黑暗中的麻袋",
  text: (s) => "夜色已深，你像往常一样走在回家那条熟悉的路上，盘算着明天的事。身后突然传来一阵急促逼近的脚步声，你心里刚升起一丝警觉——还没来得及回头，眼前猛地一黑，一只粗糙的麻袋已经死死罩住了你的头。几只有力的手不由分说地架住你，捂住你的嘴，连拖带拽把你塞进了一辆引擎轰鸣的车里。车子立刻疾驰起来，你被反绑着手脚，像货物一样被摁在颠簸的后座上，恐惧和窒息感一齐涌上来。黑暗中，一个毫无温度的声音贴着你耳边响起：「老实点，别喊，待会儿给你家里打个电话，钱到了，就放你走。」你的心脏疯狂擂动，几乎要撞破胸膛——你这才意识到，新闻里那些遥远的故事，今夜真真切切地，砸到了你头上。",
  choices: [
    { label: "保持冷静，配合并暗中找机会", effect: (s) => {
        add(s, "stress", 28); add(s, "health", -14); add(s, "mood", -18);
        flag(s, "kidnap_survivor");
        if (s.stats.strategy + s.stats.insight > 90 || rnd(0.45)) { add(s, "insight", 5); add(s, "cash", -byClass(s, { mid: 200000, rich: 800000 })); return `你强迫自己把翻涌的恐惧压到喉咙以下，让大脑冷静运转。你默数车程的分钟、辨认拐弯的次数、记下绑匪的口音和每一句对话里漏出的细节。趁着他们换班松懈、押你上厕所的间隙，你用指甲在车窗内侧、在墙角，悄悄留下了一道道只有你懂的记号。正是这些线索，让循线追查的警方一举端掉了窝点，找到了被关押的你。赎金到底还是搭进去 ¥${byClass(s, { mid: 200000, rich: 800000 }).toLocaleString()}，但人——人是活着走出来的。获救那天你腿一软跪在地上，回家后大病了一场，可你知道，是那份没被恐惧冲垮的清醒，救了自己一命。`; }
        const ransom = byClass(s, { mid: 500000, rich: 2000000 });
        add(s, "cash", -ransom); add(s, "assets", -Math.round(ransom * 0.3));
        return `你不敢有半点反抗，绑匪让你怎样你就怎样。这边，你的家人在另一头几近崩溃地东拼西凑、变卖周转，终于凑齐了 ¥${ransom.toLocaleString()} 的赎金交了出去。深夜，蒙着眼的你被随意丢弃在某处荒郊野外，等绑匪的车声彻底消失，你才哆嗦着扯下蒙眼布，瘫坐在冰冷的泥地上，对着空无一人的旷野放声痛哭。命，是保住了。可那几天暗无天日、生死全攥在别人手里的恐惧，从此成了一道缠绕你一辈子的噩梦。往后许多年，你再也不敢一个人走夜路，听见身后的脚步声就会浑身发僵。`;
      } },
    { label: "拼死反抗，伺机逃跑", effect: (s) => {
        add(s, "stress", 24);
        flag(s, "kidnap_survivor");
        if (s.stats.body > 55 && rnd(0.5)) { add(s, "health", -20); add(s, "reputation", 4); return "你一直在等机会。趁着车子在路口停下、绑匪分神点烟的那一刹那，你猛地用尽全身力气撞开车门，连滚带爬地摔到地上，踉踉跄跄冲进路边夜市的人群，扯着早已沙哑的嗓子拼命呼救。人多眼杂，绑匪没敢追，骂了一声便扬长而去。你跌坐在围拢过来的人群中间，浑身是伤、满脸是泪，却实实在在地，用自己的命赢回了自由。事后每每想起那纵身一扑，你仍会一身冷汗——再犹豫一秒，再晚那么一点点，结局可能就完全是另一个样子。"; }
        add(s, "health", -34); add(s, "mood", -20);
        const ransom = byClass(s, { mid: 600000, rich: 2500000 });
        add(s, "cash", -ransom);
        return `你的拼死挣扎彻底激怒了那几个亡命之徒，换来的是一顿没头没脑的毒打，肋骨、脸、后背，没一处是好的。挣扎过、流血过，到最后，家里还是不得不付了 ¥${ransom.toLocaleString()} 的赎金，才把你换了回来。你带着满身淤青伤痕、和比之前深了不知多少倍的恐惧回到家，瘫在床上动弹不得。那一刻你才痛彻地懂得一个残酷的道理：在某些绝境里，所谓的骨气和尊严都是奢侈品——活着,先活着，才是压倒一切的事。`;
      } }
  ]
});

// —— 6. 电信诈骗 / 杀猪盘 ——
EVENTS.push({
  id: "ev_sudden_scam",
  module: "sudden",
  ambient: true,
  once: true,
  cond: (s) => s.age >= 22,
  title: "📱 「我是你的命中注定」",
  text: (s) => byClass(s, {
    poor: "一个温柔体贴的网友陪你聊了几个月，从早安聊到晚安，记得你每一句抱怨，懂你所有的疲惫和心酸，是这段灰暗日子里唯一的光。慢慢地，ta 开始「不经意」地向你分享一个稳赚不赔的投资门路，还截图晒自己的收益。你本就为钱发愁，再看看群里别人一张张红彤彤的盈利截图，心，一点点被烧热了。",
    mid: "线上认识的「ta」，事业有成、谈吐不凡、照片体面，对你嘘寒问暖、规划未来，没几个月就把你哄得团团转，几乎认定这就是命中注定的另一半。某天夜里，ta 压低声音、神神秘秘地向你透露了一个「内部理财平台」，说是带圈内人一起财富自由的机会，错过不再有。你不放心，特意上网查了那平台——域名、备案、客服一应俱全，看起来正规得很。",
    rich: "一个身份显赫的「投资人」在某个高端饭局上主动结识了你，递来的名片烫金锃亮，三句话不离海外项目、私募基金和资本运作，朋友圈里全是名表、豪车、游艇和与名流的合影。混熟之后，ta 神色诚恳地告诉你，手上有个稳赚不赔的盘子，门槛极高、只对真正的「圈内人」开放，是看得起你才让你进——问你，要不要一起。"
  }),
  choices: [
    { label: "心动了，先小投一笔试试水", effect: (s) => {
        const lose = Math.round((s.cash) * byClass(s, { poor: 0.6, mid: 0.4, rich: 0.5 }));
        if (rnd(0.85)) {
          add(s, "cash", -lose); add(s, "mood", -22); add(s, "stress", 18);
          flag(s, "got_scammed"); flag(s, "pig_butchered");
          return byClass(s, {
            poor: `头几笔小钱你「提现」时居然真的秒到账，那份甜头让你彻底放下了戒心。在「ta」温柔的鼓励下，你一咬牙，把攒了好几年、本想用来应急的全部身家 ¥${lose.toLocaleString()} 一股脑砸了进去，满心都是翻身的盼头。然后——某个清晨，平台再也打不开了，客服失联，「ta」的头像也变成了灰色，人间蒸发得干干净净。你瘫坐在出租屋冰冷的地板上，半天没缓过来。那是你一分一厘省出来的血汗钱啊。你浑浑噩噩去报了警，立了案，可民警那句「这类案子追赃很难」，让你的心彻底沉进了海底。`,
            mid: `尝到甜头后你越投越多，APP 里的数字一路飘红，仿佛唾手可得的财富自由。可等你终于想把本金连利息全部提现时，画风变了——客服开始一脸为难地让你「先补缴个人所得税」「再交一笔解冻保证金」，一道关卡接着一道。你像着了魔似的，为了取回那笔「巨款」，把手头能动的 ¥${lose.toLocaleString()} 一笔笔全填了进去。直到再也填不动、对方索性把你拉黑，你才如梦初醒，浑身发冷——原来从头到尾，这场杀猪盘里被精心养肥、再一刀宰掉的那头「猪」，自始至终都是你自己。`,
            rich: `「圈内人」之间，谈钱伤感情。你出手阔绰，眼皮都没怎么抬就投了 ¥${lose.toLocaleString()}，还嫌自己出手小了。结果某天，整个盘子毫无预兆地收网跑路，资金链一夜蒸发。你这才发现，那个谈吐不凡、人脉通天的「投资人」，从名片到豪车到朋友圈，全是一套精心包装、专为你这种人量身定制的假人设。钱的损失你扛得住，真正让你彻夜难眠、抬不起头的，是那份你引以为傲、自认为阅人无数的判断力——竟被人从头到尾，当成一个傻子一样耍得团团转。`
          });
        }
        add(s, "cash", -Math.round(lose * 0.1)); add(s, "insight", 4); add(s, "mood", -4);
        return "你试探着投了一小笔，账面上的收益果然喜人。可就在准备追加大额时，你心里那根弦忽然「咯噔」一下，多了个心眼——你没急着转钱，而是先去查了平台的工商备案，又拉着一个懂行的朋友帮你看了看后台。这一查，破绽立刻百出：所谓的备案是套牌的，资金根本不进监管账户。你后背瞬间沁出一层冷汗，第一时间提了现、删了对方。只小亏了点试水的钱，万幸抽身得早——倘若再多贪那么一点、再多信那么一分，今天就是万劫不复的结局。";
      } },
    { label: "感觉不对劲，截图报警", effect: (s) => {
        add(s, "insight", 5); add(s, "reputation", 2);
        if (rnd(0.3)) { add(s, "cash", 2000); add(s, "mood", 6); return "你没有冲动，而是冷静地把所有聊天记录、对方发的「资料」和那张诱你转账的二维码全部截图保存，然后一通电话打给了反诈中心。没想到你提供的线索成了关键——警方顺藤摸瓜，端掉了藏在境外的一整个诈骗团伙，解救了好几个还在被「养」着的受害者。你后来还被请去社区做了一次反诈宣传。当屏幕上那个「命中注定的真爱」露出团伙嫌疑人的真面目时，你又是后怕，又是庆幸，攥着话筒的手出了一身汗。"; }
        return "夜里你翻来覆去，越想越不对劲。把ta说过的每句话重新捋一遍，那套滴水不漏的「稳赚」话术，其实处处都是漏洞——只是当局者迷，被那点暖意和贪念蒙住了眼。你深吸一口气，截好图、拉黑了对方，把全部记录原原本本交给了反诈中心。你或许永远不会知道账户里到底躲过了多大一个窟窿，但你清楚，自己刚刚和倾家荡产擦肩而过。这份在心动时刻还能踩住刹车的清醒，价值千金。";
      } },
    { label: "果断拉黑，这种套路我见多了", effect: (s) => {
        add(s, "insight", 3); add(s, "mood", -2);
        return "「天上不会掉馅饼，掉的多半是陷阱。」你心里冷笑一声，连多余的话都懒得回，直接把对方拉黑、举报。这套「先培养感情、再引你投资」的剧本你早已在新闻和身边人的惨痛教训里见过太多遍。也许，万分之一的可能，你错过的是一段真感情；但更大的概率是，你刚刚不动声色地，省下了一笔足以让人血本无归的「智商税」。在这个真假难辨的时代，适度的多疑，有时正是一个人保护自己最后的盔甲。";
      } }
  ]
});

// —— 7. 被偷被抢 ——
